import requests
import logging
from typing import Any

_LOG = logging.getLogger(__name__)

def get_order(order_id: str) -> dict[str, Any]:
    """Fetch an order by ID."""
    if not order_id.startswith("ORD-"):
        return make_error("VALIDATION_ERROR",
                          "order_id must start with 'ORD-'")
    try:
        resp = _SESSION.get(
            f"{_BASE}/orders/{order_id}",
            timeout=10,
        )
    except requests.exceptions.Timeout:
        _LOG.warning("get_order timeout order_id=%s", order_id)
        return make_error("SERVICE_UNAVAILABLE",
                          "Order service did not respond in time. Try again shortly.",
                          retry_after_seconds=15)
    except requests.exceptions.ConnectionError as exc:
        _LOG.warning("get_order connection_error order_id=%s err=%s", order_id, exc)
        return make_error("SERVICE_UNAVAILABLE",
                          "Cannot reach the order service. Try again in a few minutes.",
                          retry_after_seconds=60)
    except Exception as exc:
        _LOG.exception("get_order unexpected error order_id=%s", order_id)
        return make_error("SERVICE_UNAVAILABLE",
                          "An unexpected error occurred. The team has been notified.")

    if resp.status_code == 404:
        return make_error("NOT_FOUND",
                          f"Order {order_id} not found.")
    if resp.status_code == 403:
        return make_error("PERMISSION_DENIED",
                          "This session cannot access that order.")
    if not resp.ok:
        _LOG.warning("get_order http_error status=%d order_id=%s", resp.status_code, order_id)
        return make_error("SERVICE_UNAVAILABLE",
                          f"Order service returned {resp.status_code}.",
                          retry_after_seconds=30)

    o = resp.json()
    return {
        "order_id":   o["id"],
        "status":     o["status"],
        "total_cents": o["total"],
        "created_at": o["created_at"],
    }

def batch_update_order_status(
    order_ids: list[str],
    new_status: str,
) -> dict[str, Any]:
    """Update multiple orders. Returns both successes and failures."""
    if new_status not in ("shipped", "delivered", "cancelled"):
        return make_error("VALIDATION_ERROR",
                          f"new_status must be shipped, delivered, or cancelled")

    successes = []
    failures = []
    for oid in order_ids:
        try:
            resp = _SESSION.patch(
                f"{_BASE}/orders/{oid}",
                json={"status": new_status},
                timeout=8,
            )
            if resp.ok:
                successes.append(oid)
            elif resp.status_code == 404:
                failures.append({"order_id": oid, "reason": "NOT_FOUND"})
            elif resp.status_code == 409:
                failures.append({"order_id": oid, "reason": "CONFLICT"})
            else:
                failures.append({"order_id": oid, "reason": "SERVICE_UNAVAILABLE"})
        except Exception:
            failures.append({"order_id": oid, "reason": "SERVICE_UNAVAILABLE"})

    return {
        "succeeded": len(successes),
        "failed":    len(failures),
        "success_ids": successes,
        "failures":    failures,
        "partial": len(failures) > 0 and len(successes) > 0,
    }

def search_orders(query: str) -> dict[str, Any]:
    resp = _SESSION.get(f"{_BASE}/orders/search", params={"q": query}, timeout=10)
    if not resp.ok:
        return make_error("SERVICE_UNAVAILABLE", f"Search returned {resp.status_code}")
    results = resp.json().get("results", [])
    # Empty results is a success, not an error
    return {
        "orders": results,
        "count": len(results),
        "query": query,
    }
    # The model sees count=0 and knows the search worked but nothing matched.
    # It does NOT receive NOT_FOUND — that would imply the search itself failed.

def get_order(order_id: str) -> dict[str, Any]:
    resp = _SESSION.get(f"{_BASE}/orders/{order_id}", timeout=10)
    if resp.status_code == 404:
        # Specific lookup — the ID does not exist
        return make_error("NOT_FOUND", f"Order {order_id} does not exist")
    if not resp.ok:
        return make_error("SERVICE_UNAVAILABLE", f"Order service returned {resp.status_code}")
    o = resp.json()
    return {"order_id": o["id"], "status": o["status"]}

import sqlalchemy.exc as sa_exc
import psycopg2

def _wrap_db_error(exc: Exception) -> dict:
    """Map database exceptions to the standard error vocabulary."""
    if isinstance(exc, (sa_exc.IntegrityError, psycopg2.IntegrityError)):
        msg = str(exc.orig) if hasattr(exc, "orig") else str(exc)
        if "unique" in msg.lower() or "duplicate" in msg.lower():
            return {"error": "CONFLICT", "message": "A record with this key already exists"}
        if "foreign key" in msg.lower() or "fk_" in msg.lower():
            return {"error": "CONFLICT",
                    "message": "Operation would violate a referential integrity constraint"}
    if isinstance(exc, (sa_exc.OperationalError, psycopg2.OperationalError)):
        return {"error": "SERVICE_UNAVAILABLE",
                "message": "Database is temporarily unavailable",
                "retry_after_seconds": 30}
    if isinstance(exc, sa_exc.NoResultFound):
        return {"error": "NOT_FOUND", "message": "Record not found"}
    # Fallback
    return {"error": "SERVICE_UNAVAILABLE",
            "message": "An unexpected database error occurred"}

# Usage in a handler:
def get_order_from_db(order_id: str) -> dict:
    try:
        with _ENGINE.connect() as conn:
            row = conn.execute(
                text("SELECT * FROM orders WHERE id = :id"),
                {"id": order_id}
            ).one_or_none()
        if row is None:
            return {"error": "NOT_FOUND", "message": f"Order {order_id} not found"}
        return {"order_id": row.id, "status": row.status, "total": row.total}
    except Exception as exc:
        return _wrap_db_error(exc)
